<?php
/**
 * 小米运动刷步数 - 单账号固定步数 API 版
 * 使用方法（GET/POST均可）：
 * user  - 账号（手机号或邮箱）
 * pwd   - 密码
 * step  - 固定步数（必填）
 *
 * 示例：
 * curl "http://你的服务器/mimotion_api_single.php?user=13800138000&pwd=123456&step=20000"
 */

date_default_timezone_set('Asia/Shanghai');

// 从 POST 获取参数，否则从 GET 获取
function param($key, $default = '') {
    return isset($_POST[$key]) ? trim($_POST[$key]) : (isset($_GET[$key]) ? trim($_GET[$key]) : $default);
}

// 脱敏账号
function desensitizeUserName($user) {
    $len = strlen($user);
    if ($len <= 8) {
        $ln = max(intval(floor($len / 3)), 1);
        return substr($user, 0, $ln) . "***" . substr($user, -$ln);
    }
    return substr($user, 0, 3) . "****" . substr($user, -4);
}

// 获取毫秒时间戳
function getTimeMs() {
    return round(microtime(true) * 1000);
}

// 生成虚拟IP
function fakeIp() {
    return "223." . rand(64, 117) . "." . rand(0, 255) . "." . rand(0, 255);
}

// 提取access_token
function getAccessToken($location) {
    if (preg_match("/access=(.*?)&/", $location, $m)) {
        return $m[1];
    }
    return null;
}

class MiMotionRunner {
    private $user;
    private $password;
    private $fakeIp;
    public $logStr = "";
    public $invalid = false;

    function __construct($user, $passwd) {
        if (!$user || !$passwd) {
            $this->invalid = true;
            $this->logStr .= "用户名或密码填写有误！\n";
            return;
        }
        if (strpos($user, "+86") === false && strpos($user, "@") === false) {
            $user = "+86" . $user;
        }
        $this->user = $user;
        $this->password = $passwd;
        $this->fakeIp = fakeIp();
    }

    private function curlPost($url, $data, $headers = [], $follow = true) {
        $ch = curl_init();
        curl_setopt_array($ch, [
            CURLOPT_URL => $url,
            CURLOPT_POST => true,
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_POSTFIELDS => $data,
            CURLOPT_HTTPHEADER => $headers,
            CURLOPT_FOLLOWLOCATION => $follow,
            CURLOPT_HEADER => true,
            CURLOPT_TIMEOUT => 10
        ]);
        $res = curl_exec($ch);
        $header_size = curl_getinfo($ch, CURLINFO_HEADER_SIZE);
        $header = substr($res, 0, $header_size);
        $body = substr($res, $header_size);
        curl_close($ch);
        return [$header, $body];
    }

    private function curlGetJson($url, $headers = []) {
        $ch = curl_init();
        curl_setopt_array($ch, [
            CURLOPT_URL => $url,
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_HTTPHEADER => $headers,
            CURLOPT_TIMEOUT => 10
        ]);
        $res = curl_exec($ch);
        curl_close($ch);
        return json_decode($res, true);
    }

    public function login() {
        $url1 = "https://api-user.huami.com/registrations/{$this->user}/tokens";
        $headers = [
            "Content-Type: application/x-www-form-urlencoded;charset=UTF-8",
            "User-Agent: Mozilla/5.0 (iPhone; CPU iPhone OS 14_7_1 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko)",
            "X-Forwarded-For: {$this->fakeIp}"
        ];
        $data1 = http_build_query([
            "client_id" => "HuaMi",
            "password" => $this->password,
            "redirect_uri" => "https://s3-us-west-2.amazonaws.com/hm-registration/successsignin.html",
            "token" => "access"
        ]);
        list($header1,) = $this->curlPost($url1, $data1, $headers, false);
        if (!preg_match("/Location: (.*?)\r/i", $header1, $m)) {
            return [0,0];
        }
        $code = getAccessToken($m[1]);
        if (!$code) {
            return [0,0];
        }
        $url2 = "https://account.huami.com/v2/client/login";
        $data2 = http_build_query([
            "app_name" => "com.xiaomi.hm.health",
            "app_version" => "4.6.0",
            "code" => $code,
            "country_code" => "CN",
            "device_id" => "2C8B4939-0CCD-4E94-8CBA-CB8EA6E613A1",
            "device_model" => "phone",
            "grant_type" => "access_token",
            "third_name" => "huami_phone"
        ]);
        list(, $body2) = $this->curlPost($url2, $data2, $headers);
        $res = json_decode($body2, true);
        return [$res["token_info"]["login_token"] ?? 0, $res["token_info"]["user_id"] ?? 0];
    }

    public function getAppToken($login_token) {
        $url = "https://account-cn.huami.com/v1/client/app_tokens?app_name=com.xiaomi.hm.health&login_token={$login_token}";
        $headers = ["User-Agent: MiFit/5.3.0 (iPhone; iOS 14.7.1; Scale/3.00)", "X-Forwarded-For: {$this->fakeIp}"];
        $res = $this->curlGetJson($url, $headers);
        return $res['token_info']['app_token'] ?? '';
    }

    public function loginAndPostStep($step) {
        if ($this->invalid) return ["账号或密码配置有误", false];
        list($login_token, $userid) = $this->login();
        if (!$login_token) return ["登录失败！", false];
        $app_token = $this->getAppToken($login_token);

        $today = date("Y-m-d");
        $data_json = '%5B%7B%22data_hr%22%3A%22%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F9L%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2FVv%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F0v%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F9e%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F0n%5C%2Fa%5C%2F%5C%2F%5C%2FS%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F0b%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F1FK%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2FR%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F9PTFFpaf9L%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2FR%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F0j%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F9K%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2FOv%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2Fzf%5C%2F%5C%2F%5C%2F86%5C%2Fzr%5C%2FOv88%5C%2Fzf%5C%2FPf%5C%2F%5C%2F%5C%2F0v%5C%2FS%5C%2F8%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2FSf%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2Fz3%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F0r%5C%2FOv%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2FS%5C%2F9L%5C%2Fzb%5C%2FSf9K%5C%2F0v%5C%2FRf9H%5C%2Fzj%5C%2FSf9K%5C%2F0%5C%2F%5C%2FN%5C%2F%5C%2F%5C%2F%5C%2F0D%5C%2FSf83%5C%2Fzr%5C%2FPf9M%5C%2F0v%5C%2FOv9e%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2FS%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2F%5C%2Fzv%5C%2F%5C%2Fz7%5C%2FO%5C%2F83%5C%2Fzv%5C%2FN%5C%2F83%5C%2Fzr%5C%2FN%5C%2F86%5C%2Fz%5C%2F%5C%2FNv83%5C%2Fzn%5C%2FXv84%5C%2Fzr%5C%2FPP84%5C%2Fzj%5C%2FN%5C%2F9e%5C%2Fzr%5C%2FN%5C%2F89%5C%2F03%5C%2FP%5C%2F89%5C%2Fz3%5C%2FQ%5C%2F9N%5C%2F0v%5C%2FTv9C%5C%2F0H%5C%2FOf9D%5C%2Fzz%5C%2FOf88%5C%2Fz%5C%2F%5C%2FPP9A%5C%2Fzr%5C%2FN%5C%2F86%5C%2Fzz%5C%2FNv87%5C%